@staticmethod
def get_mastery_snapshot(session_id: str) -> dict | None:
    """返回当前技能掌握度快照 + 最后活动时间.

    Returns:
        {"skills": {"python_list": 0.73, "python_loop": 0.45},
         "total_skills": 2,
         "last_active_utc": "2026-05-10T12:00:00.000Z"}
        或 None (无数据时)
    """
    try:
        from src.coach.persistence import SessionPersistence
        p = SessionPersistence(session_id)
        profile = p.get_profile()
        masteries = profile.get("skill_masteries", {})
        if not masteries:
            return None
        return {
            "skills": {k: round(float(v), 4) for k, v in masteries.items()},
            "total_skills": len(masteries),
            "last_active_utc": profile.get("last_active", None),
        }
    except Exception:
        return None
